def _resolve_env(value: str, env_var: str) -> str:
    """Resolve ${VAR} placeholders or plain strings, favouring the env var."""
    # If the YAML value is a placeholder like ${NEO4J_PASSWORD}, resolve it
    if value.startswith("${") and value.endswith("}"):
        env_key = value[2:-1]
        return os.environ.get(env_key, "")
    return os.environ.get(env_var, value)


def load_config(config_path: Path | None = None) -> PipelineConfig:
    """Load configuration from a YAML file, applying sensible defaults otherwise."""
    if config_path and config_path.exists():
        config = PipelineConfig.from_yaml(config_path)
    else:
        config = PipelineConfig()

    # Environment variable overrides for Neo4j (takes precedence over YAML)
    config.neo4j_uri = os.environ.get("NEO4J_URI", config.neo4j_uri)
    config.neo4j_user = os.environ.get("NEO4J_USER", config.neo4j_user)
    config.neo4j_password = os.environ.get("NEO4J_PASSWORD", config.neo4j_password)

    return config

@main.command()
@click.option(
    "-o", "--output",
    "output_dir",
    default="./output",
    type=click.Path(),
    help="Pipeline output directory containing knowledge_graph.json.",
)
def neo4j_upload(output_dir: str) -> None:
    """Clear Neo4j database and upload the generated knowledge graph."""
    from kg_generator.export.neo4j_upload import upload_from_output

    click.echo(" Clearing Neo4j database and uploading knowledge graph...")
    upload_from_output(Path(output_dir))
    click.echo(" Done! Knowledge graph uploaded to Neo4j.")


if __name__ == "__main__":
    main()
